import{_ as a,c as e,a as l,o as t}from"./app-CEcM0piI.js";const s={};function n(r,i){return t(),e("div",null,i[0]||(i[0]=[l('<h2 id="display" tabindex="-1"><a class="header-anchor" href="#display"><span>display</span></a></h2><p>display属性用于设置一个元素应如何显示。</p><ul><li>display : none; 隐藏对象</li><li>display : block; 除了转换为块级元素之外，同时还有显示元素的意思</li></ul><p>display隐藏元素后不再占有原来的位置。</p><h2 id="visibility" tabindex="-1"><a class="header-anchor" href="#visibility"><span>visibility</span></a></h2><p>visibility属性用于指定一个元素应可见还是隐藏。</p><ul><li>visibility : visible; 元素可视</li><li>visibility : hidden; 元素隐藏</li></ul><p>visibility隐藏元素后，继续占有原来的位置。</p><h2 id="overflow" tabindex="-1"><a class="header-anchor" href="#overflow"><span>overflow</span></a></h2><p>对溢出的内容进行显示设置</p><ul><li>visible : 不剪切内容也不添加滚动条</li><li>hidden : 不显示超过对象尺寸的内容，超出的部分隐藏掉</li><li>scroll : 不管超出内容否，总是显示滚动条</li><li>auto : 超出自动显示滚动条，不超出不显示滚动条</li></ul>',11)]))}const p=a(s,[["render",n]]),d=JSON.parse('{"path":"/front/css/7/","title":"7 元素的显示与隐藏","lang":"zh-CN","frontmatter":{"title":"7 元素的显示与隐藏","createTime":"2025/06/18 21:06:06","permalink":"/front/css/7/"},"readingTime":{"minutes":0.69,"words":206},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/7 元素的显示与隐藏.md","headers":[]}');export{p as comp,d as data};
